\begin{tikzpicture}[
  box/.style={draw, rounded corners=3pt, minimum width=2.2cm, minimum height=0.7cm, align=center, font=\small, fill=white},
  tgw/.style={draw, circle, minimum size=1.1cm, align=center, font=\footnotesize\bfseries, fill=orange!20},
  arr/.style={-{Stealth}, thick},
  dasharr/.style={-{Stealth}, thick, dashed, red},
  region/.style={draw=gray!60, dashed, rounded corners=5pt, inner sep=8pt}
