\node[box, fill=blue!10] (pProd1) at (-7, 2.5) {Prod VPC\\(Primary)};
\node[box, fill=yellow!15] (pDev1) at (-7, 0.8) {Dev VPC\\(Primary)};
\node[box, fill=green!10] (dcgw) at (-7, -0.9) {Direct Connect\\Gateway};
\node[tgw] (tgw1) at (-4.5, 1.0) {TGW\\Primary};

\draw[arr] (pProd1) -- (tgw1);
\draw[arr] (pDev1) -- (tgw1);
\draw[arr] (dcgw) -- (tgw1);

\begin{scope}[on background layer]
  \node[region, fit=(pProd1)(pDev1)(dcgw)(tgw1), label=above:{\textbf{Primary Region}}] {};
\end{scope}

% --- Secondary Region (right) ---
\node[box, fill=blue!10] (pProd2) at (7, 2.5) {Prod VPC\\(Secondary)};
\node[box, fill=yellow!15] (pDev2) at (7, 0.8) {Dev VPC\\(Secondary)};
\node[tgw] (tgw2) at (4.5, 1.6) {TGW\\Secondary};

\draw[arr] (pProd2) -- (tgw2);
\draw[arr] (pDev2) -- (tgw2);

\begin{scope}[on background layer]
  \node[region, fit=(pProd2)(pDev2)(tgw2), label=above:{\textbf{Secondary Region}}] {};
\end{scope}

% --- TGW Peering ---
\draw[arr, thick, orange] (tgw1) -- node[above, font=\footnotesize]{TGW Peering} (tgw2);

% --- Route Table annotations ---
\node[box, fill=blue!20, font=\footnotesize] (rt1prod) at (-3.0, -0.8) {Prod RT\\(TGW Primary)};
\node[box, fill=yellow!30, font=\footnotesize] (rt1dev) at (-3.0, -2.2) {Dev RT\\(TGW Primary)};

\node[box, fill=blue!20, font=\footnotesize] (rt2prod) at (3.0, -0.8) {Prod RT\\(TGW Secondary)};
\node[box, fill=yellow!30, font=\footnotesize] (rt2dev) at (3.0, -2.2) {Dev RT\\(TGW Secondary)};

\draw[arr, blue!60] (tgw1) -- (rt1prod);
\draw[arr, yellow!70!black] (tgw1) -- (rt1dev);
\draw[arr, blue!60] (tgw2) -- (rt2prod);
\draw[arr, yellow!70!black] (tgw2) -- (rt2dev);

\draw[arr, blue!60, dashed] (rt1prod) -- node[below, font=\footnotesize]{Prod only} (rt2prod);
\draw[dasharr] (rt1dev) -- node[below, font=\footnotesize]{No cross-Region} (rt2dev);

