\begin{tikzpicture}[
  vpc/.style={draw, rounded corners=4pt, minimum width=2.4cm, minimum height=0.85cm, align=center, fill=white, font=\small\bfseries},
  tgw/.style={draw, circle, minimum size=1.2cm, align=center, fill=yellow!40, font=\tiny\bfseries},
  regionbox/.style={draw, dashed, rounded corners=8pt, inner sep=12pt, thick},
  arr/.style={-{Stealth[length=5pt]}, thick},
  barr/.style={{Stealth[length=5pt]}-{Stealth[length=5pt]}, thick}
]

% ---- Primary Region ----
\begin{scope}
  \node[vpc] (vpcA) at (-2.8, 2.0) {VPC A\\{\tiny Hub}};
  \node[vpc] (vpcB) at (2.8, 2.0) {VPC B\\{\tiny Inspection}};
  \node[vpc] (vpcC) at (0, -1.6) {VPC C\\{\tiny Spoke}};
  \node[tgw] (tgwP) at (0, 0.6) {TGW\\{\tiny Primary}};

  \draw[arr] (vpcA) -- (tgwP);
  \draw[arr] (vpcB) -- (tgwP);
  \draw[arr] (vpcC) -- (tgwP);

  \node[regionbox, fit=(vpcA)(vpcB)(vpcC)(tgwP), label={[font=\small\itshape]above:Primary Region}] (pr) {};
\end{scope}

% ---- Secondary Region ----
\node[vpc] (vpcD) at (8.5, 0.6) {VPC D\\{\tiny Spoke}};
\node[tgw] (tgwS) at (5.8, 0.6) {TGW\\{\tiny Secondary}};
\draw[arr] (vpcD) -- (tgwS);
\node[regionbox, fit=(vpcD)(tgwS), label={[font=\small\itshape]above:Secondary Region}] (sr) {};

% ---- Inter-region TGW peering ----
\draw[barr, bend left=12] (tgwP) to node[above, font=\tiny, align=center] {TGW Peering\\(Inter-region)} (tgwS);

% ---- Inspection path annotation ----
\node[font=\tiny, text=gray, align=center] at (0, -2.9) {VPC C $\rightarrow$ TGW $\rightarrow$ VPC B (inspect) $\rightarrow$ TGW $\rightarrow$ VPC A};
\node[font=\tiny, text=gray, align=center] at (0, -3.4) {Unsolicited VPC B $\rightarrow$ VPC C blocked via isolated route tables};

\end{tikzpicture}
